import { describe, expect, it } from "vitest";
import { priceOrder } from "../src/pricing.js";

// Behavior under test (see src/pricing.js):
//   priceOrder(lines, coupon?) -> { subtotalCents, discountCents, totalCents }
//   - subtotalCents = sum of unitCents * qty; [] -> all zeros
//   - qty must be a positive integer, else RangeError
//   - tier discount: 10% of subtotal (rounded, .5 up) when subtotal >= 10000
//   - coupon discount: capped pct (0-100, >30 -> 30) of the subtotal AFTER the
//     tier discount, rounded (.5 up)
//   - discountCents = tier + coupon;  totalCents = subtotal - discountCents

describe("priceOrder — subtotal", () => {
  it("returns all zeros for an empty order", () => {
    expect(priceOrder([])).toEqual({
      subtotalCents: 0,
      discountCents: 0,
      totalCents: 0,
    });
  });

  it("prices a single line as unitCents * qty", () => {
    expect(priceOrder([{ unitCents: 500, qty: 3 }])).toEqual({
      subtotalCents: 1500,
      discountCents: 0,
      totalCents: 1500,
    });
  });

  it("sums unitCents * qty across multiple lines", () => {
    expect(
      priceOrder([
        { unitCents: 1000, qty: 2 },
        { unitCents: 250, qty: 4 },
      ]),
    ).toEqual({
      subtotalCents: 3000,
      discountCents: 0,
      totalCents: 3000,
    });
  });

  it("does not discount an order just below the tier threshold", () => {
    expect(priceOrder([{ unitCents: 9999, qty: 1 }])).toEqual({
      subtotalCents: 9999,
      discountCents: 0,
      totalCents: 9999,
    });
  });
});

describe("priceOrder — qty validation", () => {
  it("throws RangeError for a fractional qty", () => {
    expect(() => priceOrder([{ unitCents: 100, qty: 1.5 }])).toThrow(RangeError);
  });

  it("throws RangeError for qty of zero", () => {
    expect(() => priceOrder([{ unitCents: 100, qty: 0 }])).toThrow(RangeError);
  });

  it("throws RangeError for a negative qty", () => {
    expect(() => priceOrder([{ unitCents: 100, qty: -2 }])).toThrow(RangeError);
  });

  it("throws RangeError for a NaN qty", () => {
    expect(() => priceOrder([{ unitCents: 100, qty: NaN }])).toThrow(RangeError);
  });

  it("throws RangeError for a non-numeric qty", () => {
    expect(() => priceOrder([{ unitCents: 100, qty: "3" }])).toThrow(RangeError);
  });

  it("includes the offending qty in the error message", () => {
    expect(() => priceOrder([{ unitCents: 100, qty: 1.5 }])).toThrow(
      /invalid qty 1\.5/,
    );
  });

  it("rejects the whole order if any line has an invalid qty", () => {
    expect(() =>
      priceOrder([
        { unitCents: 100, qty: 2 },
        { unitCents: 100, qty: 0 },
      ]),
    ).toThrow(RangeError);
  });

  it("accepts a large positive integer qty", () => {
    expect(priceOrder([{ unitCents: 1, qty: 250 }])).toEqual({
      subtotalCents: 250,
      discountCents: 0,
      totalCents: 250,
    });
  });
});

describe("priceOrder — tier discount", () => {
  it("applies 10% off at exactly the 10000-cent threshold", () => {
    expect(priceOrder([{ unitCents: 10000, qty: 1 }])).toEqual({
      subtotalCents: 10000,
      discountCents: 1000,
      totalCents: 9000,
    });
  });

  it("rounds the tier discount to the nearest cent with .5 rounding up", () => {
    // 10005 * 0.10 = 1000.5 -> 1001
    expect(priceOrder([{ unitCents: 10005, qty: 1 }])).toEqual({
      subtotalCents: 10005,
      discountCents: 1001,
      totalCents: 9004,
    });
  });
});

describe("priceOrder — coupon discount", () => {
  it("applies the coupon percentage when below the tier threshold", () => {
    // no tier: 30% of 5000 = 1500
    expect(priceOrder([{ unitCents: 5000, qty: 1 }], { pct: 30 })).toEqual({
      subtotalCents: 5000,
      discountCents: 1500,
      totalCents: 3500,
    });
  });

  it("treats a 0% coupon as no discount", () => {
    expect(priceOrder([{ unitCents: 5000, qty: 1 }], { pct: 0 })).toEqual({
      subtotalCents: 5000,
      discountCents: 0,
      totalCents: 5000,
    });
  });

  it("caps coupons above 30% at 30%", () => {
    const capped = priceOrder([{ unitCents: 5000, qty: 1 }], { pct: 50 });
    const atCap = priceOrder([{ unitCents: 5000, qty: 1 }], { pct: 30 });
    expect(capped).toEqual(atCap);
    expect(capped.discountCents).toBe(1500);
  });

  it("does not cap a coupon of exactly 30%", () => {
    // 30% is at the cap boundary and must apply in full.
    expect(priceOrder([{ unitCents: 5000, qty: 1 }], { pct: 30 }).discountCents).toBe(
      1500,
    );
  });

  it("rounds the coupon discount to the nearest cent with .5 rounding up", () => {
    // 15 * 0.10 = 1.5 -> 2
    expect(priceOrder([{ unitCents: 15, qty: 1 }], { pct: 10 })).toEqual({
      subtotalCents: 15,
      discountCents: 2,
      totalCents: 13,
    });
  });
});

describe("priceOrder — tier and coupon interaction", () => {
  it("applies the coupon to the subtotal AFTER the tier discount", () => {
    // subtotal 10000 -> tier 1000 (10%), leaving 9000.
    // coupon 10% is taken on 9000 (= 900), NOT on the 10000 subtotal (= 1000).
    // discount = 1000 + 900 = 1900; total = 8100.
    expect(priceOrder([{ unitCents: 10000, qty: 1 }], { pct: 10 })).toEqual({
      subtotalCents: 10000,
      discountCents: 1900,
      totalCents: 8100,
    });
  });

  it("combines tier and coupon rounding independently", () => {
    // subtotal 12345 -> tier round(1234.5) = 1235, leaving 11110.
    // coupon 15% -> round(1666.5) = 1667.  discount = 2902; total = 9443.
    expect(priceOrder([{ unitCents: 12345, qty: 1 }], { pct: 15 })).toEqual({
      subtotalCents: 12345,
      discountCents: 2902,
      totalCents: 9443,
    });
  });

  it("reports discountCents as the sum of the tier and coupon discounts", () => {
    const { subtotalCents, discountCents, totalCents } = priceOrder(
      [{ unitCents: 10000, qty: 1 }],
      { pct: 10 },
    );
    expect(discountCents).toBe(1900);
    expect(totalCents).toBe(subtotalCents - discountCents);
  });
});

describe("priceOrder — result invariants", () => {
  it("always satisfies total = subtotal - discount", () => {
    const cases = [
      [[], undefined],
      [[{ unitCents: 500, qty: 3 }], undefined],
      [[{ unitCents: 10000, qty: 1 }], undefined],
      [[{ unitCents: 10000, qty: 1 }], { pct: 10 }],
      [[{ unitCents: 12345, qty: 1 }], { pct: 15 }],
      [[{ unitCents: 5000, qty: 1 }], { pct: 50 }],
    ];
    for (const [lines, coupon] of cases) {
      const { subtotalCents, discountCents, totalCents } = priceOrder(lines, coupon);
      expect(totalCents).toBe(subtotalCents - discountCents);
    }
  });
});

